INSERT INTO products (id, name, description, price, brand, rating) VALUES
(1, 'Wireless Noise Cancelling Headphones', 'Over-ear Bluetooth headphones with active noise cancellation and 30-hour battery life.', 199.99, 'Sony', 4.8),
(2, 'Smart Fitness Watch', 'Water-resistant fitness smartwatch with heart rate monitor, GPS, and sleep tracking.', 149.50, 'Apple', 4.7),
(3, 'Mechanical Gaming Keyboard', 'RGB backlit mechanical keyboard with blue switches and aluminum frame.', 89.99, 'Keychron', 4.6),
(4, '4K Ultra HD Monitor', '27-inch 4K UHD monitor with IPS panel and HDR support.', 329.00, 'Acer', 4.6),
(5, 'Portable External SSD 1TB', 'High-speed USB-C external solid state drive with 1TB storage capacity.', 119.95, 'Portronics',4.5);

INSERT INTO reviews (author, rating, content, productId) VALUES
('Rahul Menon', 5, 'I have been using these headphones for a couple of weeks now and the noise cancellation is absolutely amazing. I travel frequently and this has made flights so much more comfortable. The sound quality is crisp with deep bass and clear vocals. Battery life easily lasts multiple days and the build quality feels very premium. Highly recommended for anyone who listens to music daily.', 1),
('Anjali Nair', 4, 'The headphones are very comfortable to wear for long hours and the noise cancelling works well in office environments. Sound quality is good but I expected slightly more bass. The Bluetooth connection is stable and the battery life is excellent. Overall I am very happy with this purchase.', 1),
('Vikram Pillai', 5, 'Excellent headphones with premium feel and great sound quality. I use them for both music and online meetings and the microphone clarity is very good. Noise cancellation blocks out fan noise and traffic sounds effectively. Definitely worth the price.', 1),
('Sneha Joseph', 4, 'Very good build quality and comfortable ear cushions. I can wear them for hours without discomfort. The sound is balanced and clear. The only downside is that the carrying case is a bit bulky, but otherwise the product is fantastic.', 1),
('Arjun Varghese', 5, 'These are the best wireless headphones I have owned so far. Battery life is outstanding and the fast charging feature is very useful. Noise cancellation is perfect for working in noisy environments. I would definitely recommend this product.', 1),

('Kiran Thomas', 5, 'This fitness watch has become part of my daily routine. The step tracking, heart rate monitoring, and sleep tracking all seem very accurate. The battery lasts almost a week and the display is bright even in sunlight. Very useful for tracking workouts and daily activity.', 2),
('Meera Das', 4, 'I like the design and the watch is very comfortable to wear all day. The fitness tracking features are helpful and the mobile app is easy to use. GPS tracking works well during my runs. Battery life could be slightly better but still good overall.', 2),
('Sanjay Kumar', 4, 'Good smartwatch for the price with many useful health tracking features. Notifications from the phone work well and the interface is smooth. I mainly use it for step tracking and heart rate monitoring and it performs well.', 2),
('Divya R', 5, 'Very impressed with this fitness watch. Sleep tracking insights are very helpful and the workout modes are accurate. The watch is lightweight and stylish so I can wear it all day without any issues.', 2),
('Rohit Babu', 4, 'Great value for money fitness watch. Easy to set up and use. The battery life is good and the watch charges quickly. It tracks steps, calories, and heart rate accurately. I would recommend it for beginners.', 2),

('Akhil S', 5, 'This mechanical keyboard is fantastic for both gaming and typing. The keys are very responsive and the tactile feedback from the blue switches is very satisfying. RGB lighting looks amazing and can be customized easily. Build quality is solid and feels durable.', 3),
('Neethu Paul', 4, 'I bought this keyboard mainly for typing and I really enjoy using it. The keys are clicky and comfortable. The RGB lighting effects are beautiful. The keyboard is slightly heavy but that also makes it feel premium and stable on the desk.', 3),
('Manu George', 5, 'Excellent keyboard for gamers. The response time is great and the keys feel very accurate. I also like the aluminum body which makes it feel strong and durable. Definitely a great purchase for gaming setup.', 3),
('Anoop Krishnan', 4, 'Very good mechanical keyboard with bright RGB lighting and solid build quality. The keys are a bit loud but that is expected with blue switches. Overall performance is very good and I am satisfied.', 3),
('Lakshmi N', 5, 'This is my first mechanical keyboard and I love typing on it. The key travel is perfect and it improves typing speed. The RGB lighting adds a nice aesthetic to my desk setup. Highly recommended.', 3),

('Nithin Raj', 5, 'The 4K monitor display quality is stunning. Colors are very accurate and the screen is very sharp. I use it for both work and watching movies and the experience is excellent. The stand is sturdy and setup was very easy.', 4),
('Priya Menon', 4, 'Very clear and bright display with good color reproduction. The screen size is perfect for multitasking and productivity work. HDR support is decent. Overall very good monitor for the price.', 4),
('Abhishek Nair', 5, 'Amazing monitor for video editing and design work. The IPS panel provides great viewing angles and color accuracy. Text is very sharp and the 4K resolution makes a huge difference.', 4),
('Sreejith P', 4, 'Good build quality and excellent display clarity. The monitor works perfectly with my laptop via HDMI. The only thing missing is built-in speakers but otherwise it is a great monitor.', 4),
('Athira S', 5, 'I am very happy with this monitor. The display is crystal clear and perfect for coding, watching videos, and general use. The thin bezels make it look modern and stylish.', 4),

('Deepak R', 5, 'This external SSD is extremely fast and very convenient to carry around. File transfer speeds are very high and I use it for backing up large video files. The build quality is solid and the drive is very compact.', 5),
('Reshma K', 4, 'Very useful portable SSD with fast transfer speeds. I use it daily for moving files between office and home computer. It is lightweight and easy to carry. Works perfectly with USB-C.', 5),
('Gokul V', 5, 'Excellent performance external SSD. Transfer speeds are much faster compared to my old external hard drive. The size is very small but storage capacity is large. Very good product.', 5),
('Anu Mathew', 4, 'Good portable SSD for everyday use. The design is sleek and it fits easily in my laptop bag. File transfers are quick and reliable. Price is slightly high but performance is great.', 5),
('Jithin Paul', 5, 'I use this SSD for storing project files and backups. The speed and reliability are excellent. Plug and play works perfectly on my laptop. Highly recommended for professionals.', 5);